import{_ as a,o as n,c as i,a as e}from"./chunks/framework.8tiMeCK-.js";const k=JSON.parse('{"title":"10.4  检测内核中的死锁与 CPU 停顿","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_debugging/ch10_4.md","filePath":"notes/linux_kernel_debugging/ch10_4.md","lastUpdated":null}'),p={name:"notes/linux_kernel_debugging/ch10_4.md"};function t(l,s,o,r,d,h){return n(),i("div",null,[...s[0]||(s[0]=[e(`<h1 id="_10-4-检测内核中的死锁与-cpu-停顿" tabindex="-1">10.4 检测内核中的死锁与 CPU 停顿 <a class="header-anchor" href="#_10-4-检测内核中的死锁与-cpu-停顿" aria-label="Permalink to &quot;10.4  检测内核中的死锁与 CPU 停顿&quot;">​</a></h1><p>上一节结尾我们聊到了 Panic 处理器里的那条「红线」：别太复杂，否则连「临终遗言」都留不下。但有时候，内核的死法更阴险——它没有立刻崩溃，也没有大喊大叫，只是突然不说话了。</p><p>这就是我们在这一节要处理的「假死」现场。</p><h3 id="死锁究竟是什么" tabindex="-1">死锁究竟是什么？ <a class="header-anchor" href="#死锁究竟是什么" aria-label="Permalink to &quot;死锁究竟是什么？&quot;">​</a></h3><p>死锁的意思很直白：系统或者某个 CPU 核心，进入了长时间无响应的状态。这比直接 Panic 更麻烦，因为它可能发生在生产环境的某个深夜，机器看似还在运行，但早就卡死了。</p><p>为了抓住这种幽灵般的故障，我们需要更高级的监控手段。在看具体的内核检测机制之前，我们先来花点时间把底层的「看门狗」概念捋清楚——它是所有检测机制的物理基础。</p><h4 id="关于看门狗的简短说明" tabindex="-1">关于看门狗的简短说明 <a class="header-anchor" href="#关于看门狗的简短说明" aria-label="Permalink to &quot;关于看门狗的简短说明&quot;">​</a></h4><p>看门狗本质上是一个监控程序。它的逻辑非常简单：我隔一段时间给你发个心跳（ping），如果你在规定时间内没回应，我就认为你挂了，然后强制重启系统。</p><p>在 Linux 生态里，看门狗分几种形态：</p><ol><li><strong>硬件看门狗</strong>：这是直接焊在板子上的独立芯片或者模块。它连在系统的复位电路上，一旦触发，物理上直接拉复位引脚。驱动这东西通常很依赖具体的板子，内核为此提供了一个通用框架，方便驱动开发者去对接各种乱七八糟的硬件芯片。</li><li><strong>软件看门狗</strong>：这就是内核里的 <code>softdog</code> 驱动。它没有硬件那么暴力，但在很多场景下够用了。它在内核配置里的位置是 <code>Device Drivers | Watchdog Timer Support</code>，对应的配置项是 <code>CONFIG_SOFT_WATCHDOG</code>。</li></ol><p>不过，光有内核模块还不够。通常我们需要一个用户空间的守护进程来配合它。这个守护进程的工作就是定期去喂狗（通常就是往 <code>/dev/watchdog</code> 里写点东西，或者发 ioctl）。如果这个守护进程因为系统卡死而无法工作，喂狗超时，系统就会被重启。</p><p>在很多生产环境的内核里（比如我们在本书中构建的 5.10.60 定制内核），我们会把 <code>softdog</code> 编译成模块：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CONFIG_SOFT_WATCHDOG=m</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>一旦加载，你就会在系统中看到一个名为 <code>softdog</code> 的模块。</p><h4 id="动手-跑一下-softdog-和用户态-watchdog" tabindex="-1">动手：跑一下 softdog 和用户态 watchdog <a class="header-anchor" href="#动手-跑一下-softdog-和用户态-watchdog" aria-label="Permalink to &quot;动手：跑一下 softdog 和用户态 watchdog&quot;">​</a></h4><p>光说不练假把式。我们在 x86_64 的 Ubuntu 虚拟机里把这些组件跑起来看看。</p><p>首先，加载内核的 <code>softdog</code> 模块，然后手动启动用户态的 <code>watchdog</code> 守护进程（为了演示方便，我用 <code>--verbose</code> 模式跑起来）：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> modprobe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> softdog</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> watchdog</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --verbose</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[...]</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">watchdog:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> String</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;watchdog-device&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> found</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> as</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;/dev/watchdog&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">watchdog:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Variable</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;realtime&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> found</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> as</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;yes&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">watchdog:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Integer</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;priority&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> found</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[1]+  Done                    watchdog --verbose</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>现在我们确认一下它们是不是真的在跑：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ps</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> watch</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    111</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ?</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        00:00:00</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> watchdogd</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  10106</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ?</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        00:00:00</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> watchdog</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>这里有两行记录： 第一行 <code>watchdogd</code> 是内核线程（属于 softdog 驱动的一部分）。 第二行 <code>watchdog</code> 是我们刚才启动的用户态守护进程。</p><p>顺带一提，如果你的系统用的是 systemd，它本身也有内置的看门狗功能（在 <code>/etc/systemd/system.conf</code> 里配置）。</p><p><strong>⚠️ 调试警告</strong>： 看门狗在服务器上很好用，但在<strong>调试内核时是个噩梦</strong>。想象一下，你正对着 KGDB 这种交互式调试器单步执行代码，结果因为步子太慢触发了看门狗，系统直接给你重启了——这谁受得了？所以，当你准备深度调试内核时，记得把这些看门狗关掉。</p><p>好了，既然看门狗的基础已经打好了，我们可以来看看内核怎么利用这个机制（特别是 NMI）来构建更高级的检测器——针对硬锁和软锁的检测。</p><hr><h3 id="利用内核的硬锁与软锁检测器" tabindex="-1">利用内核的硬锁与软锁检测器 <a class="header-anchor" href="#利用内核的硬锁与软锁检测器" aria-label="Permalink to &quot;利用内核的硬锁与软锁检测器&quot;">​</a></h3><p>软件（甚至硬件）是不完美的。我敢打赌你肯定遇到过那种「神秘的假死」：系统没 Panic，日志也没更新，鼠标动不了，键盘没反应，屏幕定格了。</p><p>这就是 Lockup。</p><p>内核有办法检测这类问题。我们刚才提到的看门狗，在这里扮演了关键角色。内核利用 <strong>NMI Watchdog</strong>（不可屏蔽中断看门狗）以及 <strong>perf 子系统</strong>来实现硬锁和软锁的检测。</p><p>相关的配置项藏在 <code>Kernel hacking | Debug Oops, Lockups and Hangs</code> 菜单里。看图 10.8（这里假设你看到了那堆配置选项），你可能会问：既然你说这是「生产内核」，为什么没把 <code>panic_on_oops</code> 或者 <code>panic on soft/hard lockup</code> 选上？</p><p><strong>这是个好问题。</strong> 本书的「生产内核」主要是为了演示，不是真的放在机房里跑业务。如果你在做真实的产品，是否开启自动重启是个架构决策：<strong>当系统挂了，你是希望它立刻重启以求自愈，还是希望它停在原地等你来排查尸体？</strong> 如果是前者，就打开 <code>panic_on</code> 相关的选项，并配合 <code>panic=n</code> 启动参数（表示 panic 后 n 秒自动重启）。</p><p>在我们的配置里，检测功能是打开的，但不会立刻 panic。表 10.3 总结了这里涉及的关键配置、启动参数和 sysctl 控制项。</p><p>你可以用 <code>sysctl</code> 看一下你当前系统的设置（注意 <code>nmi_watchdog</code> 对应硬锁，<code>soft_watchdog</code> 对应软锁，<strong>不是</strong>指 <code>softdog</code> 模块）：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sysctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> watchdog</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kernel.nmi_watchdog</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kernel.soft_watchdog</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kernel.watchdog</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kernel.watchdog_cpumask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 0-5</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kernel.watchdog_thresh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>在这个例子里，<code>nmi_watchdog</code> 是 0，因为这是虚拟机，通常没有硬件看门狗支持。而 <code>soft_watchdog</code> 总是可用的。</p><p>现在，让我们搞清楚这些术语到底是什么意思。</p><hr><h4 id="什么是软锁" tabindex="-1">什么是软锁？ <a class="header-anchor" href="#什么是软锁" aria-label="Permalink to &quot;什么是软锁？&quot;">​</a></h4><p>软锁是一种特定的内核 Bug。</p><p>想象一下，某个任务在内核模式下陷入了一个死循环，或者因为某种原因赖在 CPU 上不下来，并且持续了很长时间。结果就是，其他任务根本没有机会在那个 CPU 核心上调度运行。这就是软锁。</p><p><strong>时间界限</strong>： 软锁的超时时间默认是 <strong>20 秒</strong>。这个值是怎么算的？它是 <code>watchdog_thresh</code> 值的两倍。 而硬锁的超时时间就是 <code>watchdog_thresh</code> 本身，默认 <strong>10 秒</strong>。</p><p>你可以查看并修改这个值：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/sys/kernel/watchdog_thresh</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">10</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>如果想改成 5 秒（意味着软锁 10 秒触发），直接往里写整数就行。写 0 则禁用检测。</p><p><strong>当软锁被检测到时会发生什么？</strong></p><p>这取决于几个配置项：</p><ol><li>如果 <code>kernel.softlockup_panic</code> sysctl 是 1，或者启动参数里有 <code>softlockup_panic=1</code>，内核会直接 <strong>Panic</strong>。</li><li>如果没开启 Panic（默认情况），内核会打印一条警告信息，并打印出卡住任务的堆栈。</li></ol><p><strong>⚠️ 注意</strong>： 如果是第二种情况（只报警没 Panic），那个导致问题的 Bug 任务会继续赖在那里，继续霸占 CPU。系统并不会自动恢复。</p><hr><h4 id="实战-在-x86-64-上触发一次软锁" tabindex="-1">实战：在 x86_64 上触发一次软锁 <a class="header-anchor" href="#实战-在-x86-64-上触发一次软锁" aria-label="Permalink to &quot;实战：在 x86_64 上触发一次软锁&quot;">​</a></h4><p>光看定义没感觉，我们来人为制造一场灾难。</p><p>思路很简单：找个倒霉的 CPU 核心，让它进入内核态，然后在这个核心上跑一个极度消耗 CPU 的死循环。</p><p>我修改了一下之前《Linux Kernel Programming Part 2》书中的一个演示模块（<code>kthread_simple</code>），往里面加了点恶意代码。具体的代码在 <code>ch10/kthread_stuck</code> 目录下。</p><p>加载这个模块（不传参数默认就是测试软锁）：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[ ... 模块加载过程 ... ]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>运行超过 20 秒后，内核的软锁看门狗就会反应过来，直接输出一个 <code>BUG()</code> 消息！看图 10.9，你会看到控制台被 <code>BUG: soft lockup ...</code> 这类 <code>KERN_EMERG</code> 级别的消息刷屏了。</p><p>除了那个显眼的 BUG 提示，看门狗还会调用 <code>dump_stack()</code> 等例程，把当前的现场状态全部吐出来：</p><ul><li>内存里的模块列表</li><li>上下文信息</li><li>CPU 寄存器快照</li><li>机器指令</li><li>最关键的：内核模式下的调用栈</li></ul><p>如果你用了我们那个便捷的 <code>PRINT_CTX()</code> 宏，你会看到类似这样的输出：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>002) [lkd/kt_stuck]:3530   |  .N.1   /* simple_kthread() */</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>注意那个 <code>.N.1</code> 格式的字符串。 第一个字符是 <code>.</code>（点），这表示<strong>硬件中断是开启的</strong>。</p><p>这符合我们的预期：在这个测试里，我们用的是普通的 <code>spin_lock()</code>，并没有关中断。这跟接下来要讲的硬锁形成了鲜明对比。</p><p><strong>别忘了自旋锁！</strong></p><p>你可能会问：既然是死循环，为什么还要拿个自旋锁？ 这就是测试的精髓所在。</p><p>自旋锁——特别是 <code>spin_lock_irqsave()</code> 这种变种——不仅仅是自旋等待，它还会<strong>关闭硬件中断</strong>。关中断有个副作用：它也顺便禁止了内核抢占。这意味着，一旦你进去了，基本上就没人能打断你了（除了 NMI）。</p><p>这正是模拟<strong>硬锁</strong>所需要的条件。</p><p>但这有个有趣的矛盾：<strong>既然中断都关了，内核看门狗怎么能检测到它卡住了呢？</strong></p><p>答案就在于 NMI（不可屏蔽中断）。NMI 的定义就是「连中断关了我也得进来」，它利用硬件性能计数器来周期性地检查 CPU 是否还在跳动。所以，即便你在代码里把中断全关了死循环，NMI 依然能破门而入，发现你正在挂机。</p><p>（当然，再次强调：我们在第 8 章讲过，持有自旋锁时必须快进快出。这里故意反其道而行之，纯粹是为了教学演示。）</p><p>如果你想深入研究软锁检测的源码，可以去 <code>kernel/watchdog.c</code> 里的 <code>watchdog_timer_fn()</code> 函数看看。</p><p>另外，如果你试图去 <code>rmmod</code> 这个恶意模块，而且没按规矩先发信号让内核线程退场，过个大概 2 分钟，<code>rmmod</code> 这个进程自己都会被检测成「Hung Task」（被卡住的任务）。我们马上就会讲到这个检测机制。</p><hr><h4 id="什么是硬锁" tabindex="-1">什么是硬锁？ <a class="header-anchor" href="#什么是硬锁" aria-label="Permalink to &quot;什么是硬锁？&quot;">​</a></h4><p>硬锁比软锁更严重。</p><p>如果说软锁是「我不让其他人跑，但我还能响应中断」，那硬锁就是「彻底封门」。 一个 CPU 核心在内核模式下陷入死循环，并且<strong>关闭了中断</strong>。这意味着，在这个核心上，连硬件中断都无法处理。</p><p><strong>时间界限</strong>： 硬锁的超时时间默认是 10 秒（<code>watchdog_thresh</code>）。</p><p><strong>当硬锁被检测到时会发生什么？</strong></p><p>同样分两种情况：</p><ol><li><strong>Panic</strong>：如果设置了 <code>nmi_watchdog=1</code> 启动参数，或者 <code>kernel.hardlockup_panic</code> 为 1，内核会直接 Panic。</li><li><strong>警告</strong>：默认情况下，它只会打印警告和堆栈。如果启动参数里有 <code>hardlockup_all_cpu_backtrace=1</code>，它还会打印所有 CPU 的堆栈回溯。</li></ol><p>同样，如果没 Panic，那个 Bug 代码会继续卡死那个核心。</p><hr><h4 id="rcu-与-cpu-停顿" tabindex="-1">RCU 与 CPU 停顿 <a class="header-anchor" href="#rcu-与-cpu-停顿" aria-label="Permalink to &quot;RCU 与 CPU 停顿&quot;">​</a></h4><p>还有一个常见的「假死」源头，来自 RCU（Read-Copy-Update）机制。</p><p>你可能听说过 RCU，它是内核里一种强大的无锁同步机制。但在使用 RCU 时，如果 CPU 陷入了长时间的中断关闭或不可抢占状态，就会导致 <strong>RCU CPU Stall</strong>。</p><p>这就好比 RCU 机制在等你读数据，结果你一直不撒手，它超时了就会报警。</p><p><strong>快速理解 RCU 的核心逻辑</strong>：</p><p>想象几个读者（R1, R2, R3）正在读一份共享数据。 这时候来了个写者，写者并不直接改数据，而是复制一份，修改副本，然后把指针原子地指向新数据。 旧的数据怎么办？必须等所有读完了的读者（R1, R2, R3）都确认读完了，才能释放旧数据。</p><p><strong>怎么确认读者读完没？</strong> RCU 的实现方式是：等待所有当前读者<strong>主动让出 CPU</strong>（比如调用调度器）。 写者会设置一个宽限期，默认长达 60 秒（<code>CONFIG_RCU_CPU_STALL_TIMEOUT</code>）。如果这么长的时间读者都还没跑完，或者 CPU 一直不调度，内核就会打印 RCU Stall 警告。</p><hr><h4 id="实战-触发硬锁-rcu-停顿" tabindex="-1">实战：触发硬锁 / RCU 停顿 <a class="header-anchor" href="#实战-触发硬锁-rcu-停顿" aria-label="Permalink to &quot;实战：触发硬锁 / RCU 停顿&quot;">​</a></h4><p>这一步比软锁麻烦点，条件比较苛刻：</p><ol><li><strong>必须是实体机</strong>：硬锁检测依赖 NMI，虚拟机通常没这东西。</li><li><strong>开启 NMI</strong>：启动参数里要加 <code>nmi_watchdog=1</code>。</li><li><strong>配置检查</strong>：<code>CONFIG_RCU_CPU_STALL_TIMEOUT</code> 要在 3 到 300 之间。</li></ol><p>配置好后，<code>sysctl</code> 应该能看到：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># sysctl -a | grep watchdog</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kernel.nmi_watchdog</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kernel.soft_watchdog</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">...</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kernel.watchdog_thresh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>现在，我们再次加载那个恶意模块 <code>ch10/kthread_stuck</code>，这次传个参数 <code>lockup_type=2</code>。 这个参数会让内核线程在持有自旋锁时，调用 <code>spin_lock_irq()</code>，<strong>把中断和抢占都关掉</strong>，然后死循环。</p><p>等一会儿，内核日志里就会炸锅。你可能会看到 NMI 中断产生的回溯，或者是 RCU CPU Stall 的警告。</p><p>日志大概长这样：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>rcu:  INFO: rcu_sched detected stalls on CPUs/tasks:</span></span>
<span class="line"><span>rcu:         3-...0: (1 GPs behind) idle=462/1/0x4000000000000000 softirq=60126/60127 fqs=6463</span></span>
<span class="line"><span>(detected by 2, t=15003 jiffies, g=127897, q=1345272)</span></span>
<span class="line"><span>Sending NMI from CPU 2 to CPUs 3:</span></span>
<span class="line"><span>NMI backtrace for cpu 3</span></span>
<span class="line"><span>CPU: 3 PID: 16351 Comm: lkd/kt_stuck Tainted: P        W  OEL 5.13.0-37-generic #42~20.04.1-Ubuntu</span></span>
<span class="line"><span>[...]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>这就是 RCU 机制发现 CPU 被关中断卡太久后发出的咆哮。</p><p>你可以通过 <code>kernel.panic_on_rcu_stall</code> sysctl 让这种情况下直接 Panic。</p><p>最后，内核其实提供了一个更专业的测试模块 <code>test_lockup</code>（<code>CONFIG_TEST_LOCKUP</code>），专门用来测试这些检测机制，比我们自己写的山寨模块要全得多。</p><p>表 10.4 总结了所有关于硬锁、软锁的关键参数和配置。</p><hr><h3 id="利用内核的-hung-task-与-workqueue-停顿检测器" tabindex="-1">利用内核的 Hung Task 与 Workqueue 停顿检测器 <a class="header-anchor" href="#利用内核的-hung-task-与-workqueue-停顿检测器" aria-label="Permalink to &quot;利用内核的 Hung Task 与 Workqueue 停顿检测器&quot;">​</a></h3><p>除了 CPU 死循环，还有一种常见的「假死」是<strong>任务卡住</strong>。</p><p>比如某个进程进入了 <code>TASK_UNINTERRUPTIBLE</code>（D 状态），并且在睡眠里赖着不醒，持续超过默认的 <strong>120 秒</strong>。这就是 Hung Task。</p><h4 id="配置-hung-task-检测" tabindex="-1">配置 Hung Task 检测 <a class="header-anchor" href="#配置-hung-task-检测" aria-label="Permalink to &quot;配置 Hung Task 检测&quot;">​</a></h4><p>还是在 <code>Kernel hacking | Debug Oops, Lockups and Hangs</code> 菜单里：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[*] Detect Hung Tasks</span></span>
<span class="line"><span>(120) Default timeout for hung task detection (in seconds)</span></span>
<span class="line"><span>[ ]   Panic (Reboot) On Hung Tasks</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>一旦开启，内核会周期性地扫描所有任务，看看有没有谁处于 D 状态且超时。</p><p>相关的参数如下：</p><ul><li><code>CONFIG_DEFAULT_HUNG_TASK_TIMEOUT</code>：编译时配置超时时间。</li><li><code>kernel.hung_task_timeout_secs</code>：运行时 sysctl，设为 0 禁用。</li><li><code>kernel.hung_task_panic</code>：发现时是否 Panic。</li></ul><p><strong>⚠️ 调试陷阱</strong>： 我们在前面提到，如果你尝试 <code>rmmod</code> 那个恶意模块却没先发信号停止内核线程，<code>rmmod</code> 进程自己可能会被卡住（因为在等待模块引用计数归零），然后被 Hung Task 检测器抓个正着。这就是个典型的踩坑案例：调试死锁的工具本身被死锁了。</p><p>除了任务卡住，内核的 Workqueue（工作队列）也有可能会停顿。如果某个工作项挂在队列里太久没执行，也会触发报警。</p><hr><h3 id="本章回响" tabindex="-1">本章回响 <a class="header-anchor" href="#本章回响" aria-label="Permalink to &quot;本章回响&quot;">​</a></h3><p>这一章我们建立了一套完整的「故障监控体系」。</p><p>从最暴力的 <strong>Panic</strong>，到利用 NMI 穿透防线的 <strong>Hard Lockup</strong> 检测，再到能发现任务在睡眠中窒息的 <strong>Hung Task</strong> 检测。本质上，我们是在给内核装上越来越多的传感器。</p><p>还记得我们在章节引子里提到的问题吗——<strong>系统没崩溃，但它卡死了，怎么办？</strong> 现在答案很清楚了：</p><ul><li>如果是 CPU 疯跑不调度，是 <strong>Soft Lockup</strong>；</li><li>如果是 CPU 关中断不响应，是 <strong>Hard Lockup</strong>；</li><li>如果是任务死等资源不醒来，是 <strong>Hung Task</strong>；</li><li>如果是 RCU 宽限期过不去，是 <strong>RCU Stall</strong>。</li></ul><p>下一章，我们将把视线从「内核自己死了」转移到「内核被外力弄死」——也就是硬件故障、内存损坏以及调试这些核弹级问题的终极手段。</p>`,121)])])}const g=a(p,[["render",t]]);export{k as __pageData,g as default};
